import { ethers } from "ethers";

const provider = new ethers.JsonRpcProvider("https://evmrpc-testnet.0g.ai");
const signer = new ethers.Wallet(process.env.STORAGE_PRIVATE_KEY, provider);

console.log("Deploying from:", signer.address);

const REGISTRY_BYTECODE = "0x608060405234801561001057600080fd5b50336000806101000a81548173ffffffffffffffffffffffffffffffffffffffff021916908373ffffffffffffffffffffffffffffffffffffffff1602179055506104a7806100606000396000f3fe";

const REGISTRY_ABI = [
  "function registerAgent(string,string,string,uint256,string) returns (uint256)",
  "function getAgent(uint256) view returns (tuple(uint256,string,string,string,uint256,address,uint256,uint256,bool,string))",
  "function agentCount() view returns (uint256)",
  "event AgentRegistered(uint256 indexed,string,address)"
];

async function deployContract(name, bytecode) {
  console.log(`Deploying ${name}...`);
  const tx = await signer.sendTransaction({
    data: bytecode,
    gasLimit: 3000000,
  });
  const receipt = await tx.wait();
  console.log(`${name} deployed at: ${receipt.contractAddress}`);
  console.log(`Explorer: https://chainscan-galileo.0g.ai/tx/${tx.hash}`);
  return receipt.contractAddress;
}

const balance = await provider.getBalance(signer.address);
console.log("Balance:", ethers.formatEther(balance), "OG");

const registryAddress = await deployContract("AgentRegistry", "");

console.log("\n✅ Deployment complete!");
console.log("AgentRegistry:", registryAddress);
console.log("\nSave these addresses!");
